INSERT INTO t_p71821556_real_estate_catalog_.ai_memory (key, value) VALUES
  ('glossary_gab', 'ГАБ (Готовый Арендный Бизнес) — объект коммерческой недвижимости, уже сданный в аренду и приносящий ежемесячный доход. Покупатель сразу получает арендный поток.'),
  ('glossary_payback', 'Окупаемость (payback) — за сколько месяцев арендный поток окупит цену объекта. Формула: цена / месячная аренда.'),
  ('glossary_caprate', 'Ставка капитализации (cap rate) — годовой доход в процентах от цены объекта. Например, 12% годовых = объект окупится за ~8 лет.'),
  ('glossary_map', 'МАП = Месячный Арендный Поток. ГАП = Годовой Арендный Поток (МАП × 12).'),
  ('glossary_lines', 'Линия расположения: 1-я линия = выход на основную улицу (трафик высокий, цена выше). 2-я линия = вглубь квартала. 3-я линия и дальше — спальные зоны.'),
  ('glossary_class', 'Класс здания: A+/A — премиум БЦ, новые. B+/B — современные, средний сегмент. C — старые здания эконом-класса.'),
  ('faq_apply', 'Чтобы оставить заявку: нажмите кнопку «Связаться» на странице объекта или на главной. Менеджер свяжется в течение часа в рабочее время.'),
  ('faq_compare', 'На сайте можно сравнить до 3 объектов: добавьте их в сравнение через иконку весов и нажмите кнопку сравнения внизу.'),
  ('faq_map', 'Все объекты есть на интерактивной карте: раздел «Карта» в меню. Можно фильтровать по типу.'),
  ('faq_favorites', 'Избранное сохраняется локально в браузере. Чтобы посмотреть — раздел «Избранное» в меню.'),
  ('rule_business_pick', 'Для кофейни/пекарни: 1-я линия, центр или ЖК, парковка, 40-100 м², электричество от 10 кВт, вытяжка.'),
  ('rule_office_pick', 'Для офиса под IT/маркетинг: класс B+ или выше, оптоволокно, парковка, кондиционер, готовый ремонт.'),
  ('rule_warehouse_pick', 'Для склада: окраина города, заезд для фур, потолки от 6 м, рампа или ворота на уровне земли.'),
  ('rule_retail_pick', 'Для магазина одежды/обуви: ТЦ или 1-я линия с витриной, проходимость от 1000 человек/день, парковка рядом.'),
  ('contact_info', 'Контакты компании: телефон и email указаны в разделе «Контакты» и в подвале сайта. Работаем с 2007 года в Краснодаре.'),
  ('process_view', 'Процесс просмотра объекта: оставляете заявку → менеджер согласовывает удобное время → выезжаем вместе на объект → оформляем сделку. Просмотр бесплатный.')
